const body = $input.first().json.body;
const message = body.message || body.edited_message;
if (!message) { return []; }
const chatid = String(message.chat.id);
const fromid = String(message.from.id);
const fromname = message.from.first_name || 'Sem nome';
const text = message.text || '';
const messageid = message.message_id;
if (!text || text.trim() === '') { return []; }
return [{ json: { chatid, fromid, fromname, text, messageid } }];

const agora = new Date();
const agoraBrasilia = new Date(agora.getTime() - 3 * 60 * 60 * 1000);
const hora = agoraBrasilia.getUTCHours();
const diaSemana = agoraBrasilia.getUTCDay();
const dentroHorario = diaSemana >= 1 && diaSemana <= 6 && hora >= 8 && hora < 18;
return [{ json: { ...$input.first().json, dentroHorario, hora, diaSemana } }];

const chatid = $input.first().json.chatid;
const fromname = $input.first().json.fromname;
const texto = 'Ola, ' + fromname + '!

A Dra. Vanessa esta fora do horario de atendimento no momento.

Se for uma urgencia, procure um servico veterinario 24 horas mais proximo.

Nos demais casos, ela retornara sua mensagem assim que possivel.';
return [{ json: { chatid, texto } }];

const eventos = $input.all();
const temEvento = eventos.length > 0 && eventos[0].json.id;
const msg = $('Extrai mensagem').first().json;
return [{ json: { chatid: msg.chatid, fromid: msg.fromid, fromname: msg.fromname, text: msg.text, vanessaOcupada: !!temEvento } }];

const caso = $('Busca caso no Neon').all();
const temCaso = caso.length > 0 && caso[0].json.casoid;
const estado = $('Avalia estado Vanessa').first().json;
const historicoRows = $('Busca historico').all();

let historico = [];
try {
  if (historicoRows.length > 0 && historicoRows[0].json.historico) {
    historico = JSON.parse(historicoRows[0].json.historico);
  }
} catch(e) { historico = []; }

historico.push({ role: 'user', content: estado.text });

let situacao;
if (!estado.vanessaOcupada) {
  situacao = 'livre';
} else if (temCaso) {
  situacao = 'ocupada_caso_antigo';
} else {
  situacao = 'ocupada_caso_novo';
}

const animalnome = temCaso ? caso[0].json.animalnome : null;
const tutornome = temCaso ? caso[0].json.tutornome : estado.fromname;

return [{ json: { chatid: estado.chatid, fromname: estado.fromname, text: estado.text, situacao, animalnome, tutornome, historico } }];

const dados = $input.first().json;
const chatid = dados.chatid;
const tutornome = dados.tutornome;
const animalnome = dados.animalnome;
const situacao = dados.situacao;
const historico = dados.historico;
let texto;
if (situacao === 'livre') {
  texto = 'Ola, ' + tutornome + '!\n\nA Dra. Vanessa esta concluindo um atendimento e retornara sua mensagem em breve.\n\nFique a vontade para relatar o que esta acontecendo que ela lera assim que puder.';
} else {
  texto = 'Ola, ' + tutornome + '!\n\nA Dra. Vanessa esta em atendimento no momento e retornara sua mensagem em breve.\n\nFique a vontade para relatar o que esta acontecendo com ' + (animalnome || 'seu animal') + ' que ela lera assim que puder.';
}
return [{ json: { chatid, texto, historico } }];

